export default App;

import { FoodItem, DashboardStats } from "../types";

const STORAGE_KEY_ITEMS = "zogdida_items";
const STORAGE_KEY_STATS = "zogdida_stats";

export const saveItems = (items: FoodItem[]) => {
  localStorage.setItem(STORAGE_KEY_ITEMS, JSON.stringify(items));
};

export const loadItems = (): FoodItem[] => {
  const data = localStorage.getItem(STORAGE_KEY_ITEMS);
  return data ? JSON.parse(data) : [];
};

export const saveStats = (stats: DashboardStats) => {
  localStorage.setItem(STORAGE_KEY_STATS, JSON.stringify(stats));
};

export const loadStats = (): DashboardStats => {
  const data = localStorage.getItem(STORAGE_KEY_STATS);
  return data ? JSON.parse(data) : {
    moneySaved: 0,
    foodSavedWeight: 0,
    wastedItemsCount: 0,
    topWastedItems: []
  };
};

export const clearAllData = () => {
  localStorage.removeItem(STORAGE_KEY_ITEMS);
  localStorage.removeItem(STORAGE_KEY_STATS);
};

import React, { useState, useEffect, useMemo } from 'react';
import { FoodItem, DashboardStats, MaturityLevel } from './types';
import { loadItems, saveItems, loadStats, saveStats, clearAllData } from './utils/storage';
import AddFoodModal from './components/AddFoodModal';
import RecipeModal from './components/RecipeModal';

const App: React.FC = () => {
  const [items, setItems] = useState<FoodItem[]>([]);
  const [stats, setStats] = useState<DashboardStats>(loadStats());
  const [view, setView] = useState<'home' | 'stats' | 'list' | 'recipes'>('home');
  const [isAddModalOpen, setIsAddModalOpen] = useState(false);
  const [selectedRecipeItem, setSelectedRecipeItem] = useState<FoodItem | null>(null);

  useEffect(() => {
    setItems(loadItems());
    if ('Notification' in window && Notification.permission === 'default') {
      Notification.requestPermission();
    }
  }, []);

  useEffect(() => {
    saveItems(items);
  }, [items]);

  useEffect(() => {
    saveStats(stats);
  }, [stats]);

  const sortedItems = useMemo(() => {
    return [...items]
      .filter(item => !item.isUsed && !item.isWasted)
      .sort((a, b) => {
        const timeA = new Date(a.expiryDate).getTime();
        const timeB = new Date(b.expiryDate).getTime();
        return timeA - timeB;
      });
  }, [items]);

  const urgentItems = useMemo(() => {
    return sortedItems;
  }, [sortedItems]);

  const shoppingListItems = useMemo(() => {
    const expiredOrUsedNames = items
      .filter(i => i.isUsed || i.isWasted)
      .map(i => i.name);
    const currentlyInFridgeNames = sortedItems.map(i => i.name);
    return Array.from(new Set(expiredOrUsedNames))
      .filter(name => !currentlyInFridgeNames.includes(name));
  }, [items, sortedItems]);

  const handleAddItem = (newItem: FoodItem) => {
    setItems(prev => [newItem, ...prev]);
  };

  const markAsUsed = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;
    setItems(prev => prev.map(i => i.id === id ? { ...i, isUsed: true } : i));
    setStats(prev => ({
      ...prev,
      moneySaved: prev.moneySaved + item.price,
      foodSavedWeight: prev.foodSavedWeight + item.weight
    }));
  };

  const markAsWasted = (id: string) => {
    const item = items.find(i => i.id === id);
    if (!item) return;
    setItems(prev => prev.map(i => i.id === id ? { ...i, isWasted: true } : i));
    setStats(prev => {
      const newTopWasted = [...prev.topWastedItems];
      if (!newTopWasted.includes(item.name)) newTopWasted.push(item.name);
      return {
        ...prev,
        wastedItemsCount: prev.wastedItemsCount + 1,
        topWastedItems: newTopWasted.slice(-5)
      };
    });
  };

  const handleResetApp = () => {
    if (window.confirm("Êtes-vous sûr de vouloir réinitialiser Zogdida ? Toutes vos données (frigo, stats, liste de courses) seront supprimées définitivement.")) {
      clearAllData();
      setItems([]);
      setStats({
        moneySaved: 0,
        foodSavedWeight: 0,
        wastedItemsCount: 0,
        topWastedItems: []
      });
      setView('home');
    }
  };

  const getUrgencyColor = (expiryDate: string) => {
    const daysLeft = Math.ceil((new Date(expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    if (daysLeft < 0) return 'bg-slate-500';
    if (daysLeft < 2) return 'bg-rose-600 shadow-lg shadow-rose-200 animate-pulse';
    if (daysLeft < 4) return 'bg-amber-500 shadow-md shadow-amber-100';
    return 'bg-emerald-500 shadow-sm shadow-emerald-100';
  };

  const getUrgencyText = (expiryDate: string) => {
    const daysLeft = Math.ceil((new Date(expiryDate).getTime() - new Date().getTime()) / (1000 * 3600 * 24));
    if (daysLeft < 0) return 'Périmé';
    if (daysLeft === 0) return "Aujourd'hui";
    if (daysLeft === 1) return 'Demain';
    return `${daysLeft} jours restants`;
  };

  const getCategoryIcon = (cat: string) => {
    switch (cat) {
      case 'Légume': return 'fa-carrot';
      case 'Fruit': return 'fa-apple-whole';
      case 'Produit laitier': return 'fa-cheese';
      case 'Charcuterie': return 'fa-bacon';
      case 'Viande/Poisson': return 'fa-fish';
      default: return 'fa-box';
    }
  };

  return (
    <div className="min-h-screen pb-32 max-w-lg mx-auto bg-slate-50 relative overflow-x-hidden">
      <header className="p-6 pb-2 flex justify-between items-center sticky top-0 bg-slate-50/90 backdrop-blur-xl z-40 border-b border-slate-100">
        <div className="flex items-center gap-3">
          <div className="bg-emerald-600 w-10 h-10 rounded-xl flex items-center justify-center text-white shadow-lg">
            <i className="fa-solid fa-leaf text-xl"></i>
          </div>
          <div>
            <h1 className="text-2xl font-black text-slate-800 tracking-tight">Zogdida</h1>
            <p className="text-[10px] font-bold text-emerald-600 uppercase tracking-[0.2em]">Anti-Gaspillage TN</p>
          </div>
        </div>
        <button 
          onClick={() => setIsAddModalOpen(true)}
          className="bg-emerald-600 text-white w-12 h-12 rounded-2xl shadow-xl shadow-emerald-200 flex items-center justify-center hover:bg-emerald-700 transition-all active:scale-90"
        >
          <i className="fa-solid fa-plus text-xl"></i>
        </button>
      </header>

      <main className="px-5 py-6">
        {view === 'home' && (
