              <div className="bg-emerald-600 rounded-[2rem] p-6 text-white shadow-xl shadow-emerald-100">
                <div className="text-4xl font-black mb-1">{stats.moneySaved} <span className="text-sm font-normal">DT</span></div>
                <div className="text-[10px] font-black uppercase tracking-widest opacity-80">Économies</div>
              </div>
              <div className="bg-amber-500 rounded-[2rem] p-6 text-white shadow-xl shadow-amber-100">
                <div className="text-4xl font-black mb-1">{(stats.foodSavedWeight / 1000).toFixed(1)} <span className="text-sm font-normal">kg</span></div>
                <div className="text-[10px] font-black uppercase tracking-widest opacity-80">Nourriture sauvée</div>
              </div>
            </div>

            <div className="bg-white rounded-[2rem] p-7 shadow-sm border border-slate-100">
              <h3 className="font-black text-slate-800 mb-6 uppercase text-xs tracking-[0.2em] flex items-center gap-2">
                <i className="fa-solid fa-triangle-exclamation text-rose-500"></i> Historique des Pertes
              </h3>
              {stats.topWastedItems.length > 0 ? (
                <ul className="space-y-4">
