import React, { useState } from 'react';
import { FoodItem, DashboardStats } from '../types';
import { clearAllData } from '../utils/storage';

interface AdminPanelProps {
  items: FoodItem[];
  stats: DashboardStats;
  onClose: () => void;
  onRefresh: () => void;
}

const AdminPanel: React.FC<AdminPanelProps> = ({ items, stats, onClose, onRefresh }) => {
  const [tab, setTab] = useState<'data' | 'system'>('data');
  const [copySuccess, setCopySuccess] = useState(false);

  const rawData = JSON.stringify({ items, stats }, null, 2);

  const handleCopy = () => {
    navigator.clipboard.writeText(rawData);
    setCopySuccess(true);
    setTimeout(() => setCopySuccess(false), 2000);
  };

  return (
    <div className="fixed inset-0 z-[60] bg-slate-900 flex flex-col animate-in slide-in-from-right duration-300">
      <header className="p-6 flex justify-between items-center border-b border-slate-800 shrink-0">
        <div>
          <h2 className="text-xl font-black text-white">Backoffice Local</h2>
          <p className="text-xs text-slate-400 font-bold uppercase tracking-widest">Console de maintenance</p>
        </div>
        <button onClick={onClose} className="w-10 h-10 rounded-full bg-slate-800 text-white flex items-center justify-center">
          <i className="fa-solid fa-xmark"></i>
        </button>
      </header>

      <div className="flex bg-slate-800 p-1 m-4 rounded-xl shrink-0">
        <button 
          onClick={() => setTab('data')}
          className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tab === 'data' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400'}`}
        >
          DONNÉES BRUTES
        </button>
        <button 
          onClick={() => setTab('system')}
          className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${tab === 'system' ? 'bg-emerald-600 text-white shadow-lg' : 'text-slate-400'}`}
        >
          SYSTÈME
        </button>
      </div>

      <div className="flex-1 overflow-y-auto px-4 pb-10">
        {tab === 'data' && (
          <div className="space-y-4">
            <div className="flex justify-between items-center">
              <h3 className="text-slate-400 text-[10px] font-black uppercase tracking-widest">Stockage LocalStorage</h3>
              <button 
                onClick={handleCopy}
                className="text-[10px] bg-slate-700 text-emerald-400 px-3 py-1 rounded-full font-bold border border-emerald-900/30"
              >
                {copySuccess ? 'COPIÉ !' : 'COPIER JSON'}
              </button>
